// Java — Queue: Enqueue, Dequeue, Peek, IsEmpty, Reset
import java.util.LinkedList;

public class Queue<T> {
    private final LinkedList<T> items = new LinkedList<>();

    // Enqueue — add element to the rear
    public void enqueue(T item) {
        items.addLast(item);
    }

    // Dequeue — remove and return front element
    public T dequeue() {
        if (isEmpty())
            throw new RuntimeException("Queue is empty.");
        return items.removeFirst();
    }

    // Peek — return front element without removing
    public T peek() {
        if (isEmpty())
            throw new RuntimeException("Queue is empty.");
        return items.getFirst();
    }

    // IsEmpty — check if queue has no elements
    public boolean isEmpty() { return items.isEmpty(); }

    // Reset — remove all elements
    public void reset() { items.clear(); }

    public int size() { return items.size(); }

    public static void main(String[] args) {
        Queue<Integer> queue = new Queue<>();
        queue.enqueue(10);
        queue.enqueue(20);
        queue.enqueue(30);

        int front = queue.peek();    // 10 — not removed
        int first = queue.dequeue(); // 10 — removed, front is now 20

        boolean empty = queue.isEmpty(); // false
        queue.reset();                   // queue is now empty
    }
}

// JavaScript — Queue: Enqueue, Dequeue, Peek, IsEmpty, Reset

class Queue {
    constructor() {
        this.items = [];
    }

    // Enqueue — add element to the rear
    enqueue(item) {
        this.items.push(item);
    }

    // Dequeue — remove and return front element
    dequeue() {
        if (this.isEmpty())
            throw new Error('Queue is empty.');
        return this.items.shift();
    }

    // Peek — return front element without removing
    peek() {
        if (this.isEmpty())
            throw new Error('Queue is empty.');
        return this.items[0];
    }

    // IsEmpty — check if queue has no elements
    isEmpty() { return this.items.length === 0; }

    // Reset — remove all elements
    reset() { this.items = []; }

    size() { return this.items.length; }
}

